1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Step = QuoteStep;
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	type QuoteResult = { premium: number };
17	type ScenarioResult = { results: QuoteResult[] };
18	
19	const quotePremium = (items: Item[]): number => {
20	  if (items.length === 0) return PROCESSING_FEE;
21	  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
22	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
23	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
24	};
25	
26	export const runScenario = (scenario: Scenario): ScenarioResult => {
27	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
28	  return { results };
29	};
